   630→
   631→static int nfp_flower_vnic_init(struct nfp_app *app, struct nfp_net *nn)
   632→{
   633→	struct nfp_flower_priv *priv = app->priv;
   634→	int err;
   635→
   636→	priv->nn = nn;
   637→
   638→	err = nfp_flower_spawn_phy_reprs(app, app->priv);
   639→	if (err)
   640→		goto err_clear_nn;
   641→
   642→	err = nfp_flower_spawn_vnic_reprs(app,
   643→					  NFP_FLOWER_CMSG_PORT_VNIC_TYPE_PF,
   644→					  NFP_REPR_TYPE_PF, 1);
   645→	if (err)
   646→		goto err_destroy_reprs_phy;
   647→
   648→	if (app->pf->num_vfs) {
   649→		err = nfp_flower_spawn_vnic_reprs(app,
   650→						  NFP_FLOWER_CMSG_PORT_VNIC_TYPE_VF,
   651→						  NFP_REPR_TYPE_VF,
   652→						  app->pf->num_vfs);
   653→		if (err)
   654→			goto err_destroy_reprs_pf;
   655→	}
   656→
   657→	return 0;
   658→
   659→err_destroy_reprs_pf:
   660→	nfp_reprs_clean_and_free_by_type(app, NFP_REPR_TYPE_PF);
   661→err_destroy_reprs_phy:
   662→	nfp_reprs_clean_and_free_by_type(app, NFP_REPR_TYPE_PHYS_PORT);
   663→err_clear_nn:
   664→	priv->nn = NULL;
   665→	return err;
   666→}
   667→
   668→static void nfp_flower_wait_host_bit(struct nfp_app *app)
   669→{
   670→	unsigned long err_at;
   671→	u64 feat;
   672→	int err;
   673→
   674→	/* Wait for HOST_ACK flag bit to propagate */
   675→	err_at = jiffies + msecs_to_jiffies(100);
   676→	do {
   677→		feat = nfp_rtsym_read_le(app->pf->rtbl,
   678→					 "_abi_flower_combined_features_global",
   679→					 &err);
   680→		if (time_is_before_eq_jiffies(err_at)) {
   681→			nfp_warn(app->cpp,
   682→				 "HOST_ACK bit not propagated in FW.\n");
   683→			break;
   684→		}
   685→		usleep_range(1000, 2000);
   686→	} while (!err && !(feat & NFP_FL_FEATS_HOST_ACK));
   687→
   688→	if (err)
   689→		nfp_warn(app->cpp,
   690→			 "Could not read global features entry from FW\n");
   691→}
   692→
   693→static int nfp_flower_sync_feature_bits(struct nfp_app *app)
   694→{
   695→	struct nfp_flower_priv *app_priv = app->priv;
   696→	int err;
   697→
   698→	/* Tell the firmware of the host supported features. */
   699→	err = nfp_rtsym_write_le(app->pf->rtbl, "_abi_flower_host_mask",
   700→				 app_priv->flower_ext_feats |
   701→				 NFP_FL_FEATS_HOST_ACK);
   702→	if (!err)
   703→		nfp_flower_wait_host_bit(app);
   704→	else if (err != -ENOENT)
   705→		return err;
   706→
   707→	/* Tell the firmware that the driver supports lag. */
   708→	err = nfp_rtsym_write_le(app->pf->rtbl,
   709→				 "_abi_flower_balance_sync_enable", 1);
   710→	if (!err) {
   711→		app_priv->flower_en_feats |= NFP_FL_ENABLE_LAG;
   712→		nfp_flower_lag_init(&app_priv->nfp_lag);
   713→	} else if (err == -ENOENT) {
   714→		nfp_warn(app->cpp, "LAG not supported by FW.\n");
   715→	} else {
   716→		return err;
   717→	}
   718→
   719→	if (app_priv->flower_ext_feats & NFP_FL_FEATS_FLOW_MOD) {
   720→		/* Tell the firmware that the driver supports flow merging. */
   721→		err = nfp_rtsym_write_le(app->pf->rtbl,
   722→					 "_abi_flower_merge_hint_enable", 1);
   723→		if (!err) {
   724→			app_priv->flower_en_feats |= NFP_FL_ENABLE_FLOW_MERGE;
   725→			nfp_flower_internal_port_init(app_priv);
   726→		} else if (err == -ENOENT) {
   727→			nfp_warn(app->cpp,
   728→				 "Flow merge not supported by FW.\n");
   729→		} else {
   730→			return err;
   731→		}
   732→	} else {
   733→		nfp_warn(app->cpp, "Flow mod/merge not supported by FW.\n");
   734→	}
   735→
   736→	return 0;
   737→}
   738→
   739→static int nfp_flower_init(struct nfp_app *app)
   740→{
   741→	u64 version, features, ctx_count, num_mems;
   742→	const struct nfp_pf *pf = app->pf;
   743→	struct nfp_flower_priv *app_priv;
   744→	int err;
   745→
   746→	if (!pf->eth_tbl) {
   747→		nfp_warn(app->cpp, "FlowerNIC requires eth table\n");
   748→		return -EINVAL;
   749→	}
   750→
   751→	if (!pf->mac_stats_bar) {
   752→		nfp_warn(app->cpp, "FlowerNIC requires mac_stats BAR\n");
   753→		return -EINVAL;
   754→	}
   755→
   756→	if (!pf->vf_cfg_bar) {
   757→		nfp_warn(app->cpp, "FlowerNIC requires vf_cfg BAR\n");
   758→		return -EINVAL;
   759→	}
   760→
   761→	version = nfp_rtsym_read_le(app->pf->rtbl, "hw_flower_version", &err);
   762→	if (err) {
   763→		nfp_warn(app->cpp, "FlowerNIC requires hw_flower_version memory symbol\n");
   764→		return err;
   765→	}
   766→
   767→	num_mems = nfp_rtsym_read_le(app->pf->rtbl, "CONFIG_FC_HOST_CTX_SPLIT",
   768→				     &err);
   769→	if (err) {
   770→		nfp_warn(app->cpp,
   771→			 "FlowerNIC: unsupported host context memory: %d\n",
   772→			 err);
   773→		err = 0;
   774→		num_mems = 1;
   775→	}
   776→
   777→	if (!FIELD_FIT(NFP_FL_STAT_ID_MU_NUM, num_mems) || !num_mems) {
   778→		nfp_warn(app->cpp,
   779→			 "FlowerNIC: invalid host context memory: %llu\n",
   780→			 num_mems);
   781→		return -EINVAL;
   782→	}
   783→
   784→	ctx_count = nfp_rtsym_read_le(app->pf->rtbl, "CONFIG_FC_HOST_CTX_COUNT",
   785→				      &err);
   786→	if (err) {
   787→		nfp_warn(app->cpp,
   788→			 "FlowerNIC: unsupported host context count: %d\n",
   789→			 err);
   790→		err = 0;
   791→		ctx_count = BIT(17);
   792→	}
   793→
   794→	/* We need to ensure hardware has enough flower capabilities. */
   795→	if (version != NFP_FLOWER_ALLOWED_VER) {
   796→		nfp_warn(app->cpp, "FlowerNIC: unsupported firmware version\n");
   797→		return -EINVAL;
   798→	}
   799→
   800→	app_priv = vzalloc(sizeof(struct nfp_flower_priv));
   801→	if (!app_priv)
   802→		return -ENOMEM;
   803→
   804→	app_priv->total_mem_units = num_mems;
   805→	app_priv->active_mem_unit = 0;
   806→	app_priv->stats_ring_size = roundup_pow_of_two(ctx_count);
   807→	app->priv = app_priv;
   808→	app_priv->app = app;
   809→	skb_queue_head_init(&app_priv->cmsg_skbs_high);
   810→	skb_queue_head_init(&app_priv->cmsg_skbs_low);
   811→	INIT_WORK(&app_priv->cmsg_work, nfp_flower_cmsg_process_rx);
   812→	init_waitqueue_head(&app_priv->reify_wait_queue);
   813→
   814→	init_waitqueue_head(&app_priv->mtu_conf.wait_q);
   815→	spin_lock_init(&app_priv->mtu_conf.lock);
   816→
   817→	err = nfp_flower_metadata_init(app, ctx_count, num_mems);
   818→	if (err)
   819→		goto err_free_app_priv;
   820→
   821→	/* Extract the extra features supported by the firmware. */
   822→	features = nfp_rtsym_read_le(app->pf->rtbl,
   823→				     "_abi_flower_extra_features", &err);
   824→	if (err)
   825→		app_priv->flower_ext_feats = 0;
   826→	else
   827→		app_priv->flower_ext_feats = features & NFP_FL_FEATS_HOST;
   828→
   829→	err = nfp_flower_sync_feature_bits(app);
   830→	if (err)
   831→		goto err_cleanup;
   832→
   833→	if (app_priv->flower_ext_feats & NFP_FL_FEATS_VF_RLIM)
   834→		nfp_flower_qos_init(app);
   835→
   836→	INIT_LIST_HEAD(&app_priv->indr_block_cb_priv);
   837→	INIT_LIST_HEAD(&app_priv->non_repr_priv);
   838→	app_priv->pre_tun_rule_cnt = 0;
   839→
   840→	return 0;
   841→
   842→err_cleanup:
   843→	if (app_priv->flower_en_feats & NFP_FL_ENABLE_LAG)
   844→		nfp_flower_lag_cleanup(&app_priv->nfp_lag);
   845→	nfp_flower_metadata_cleanup(app);
   846→err_free_app_priv:
   847→	vfree(app->priv);
   848→	return err;
   849→}
   850→
   851→static void nfp_flower_clean(struct nfp_app *app)
   852→{
   853→	struct nfp_flower_priv *app_priv = app->priv;
   854→
   855→	skb_queue_purge(&app_priv->cmsg_skbs_high);
   856→	skb_queue_purge(&app_priv->cmsg_skbs_low);
   857→	flush_work(&app_priv->cmsg_work);
   858→
   859→	if (app_priv->flower_ext_feats & NFP_FL_FEATS_VF_RLIM)
   860→		nfp_flower_qos_cleanup(app);
   861→
   862→	if (app_priv->flower_en_feats & NFP_FL_ENABLE_LAG)
   863→		nfp_flower_lag_cleanup(&app_priv->nfp_lag);
   864→
   865→	if (app_priv->flower_en_feats & NFP_FL_ENABLE_FLOW_MERGE)
   866→		nfp_flower_internal_port_cleanup(app_priv);
   867→
   868→	nfp_flower_metadata_cleanup(app);
   869→	vfree(app->priv);
   870→	app->priv = NULL;
   871→}
   872→
   873→static bool nfp_flower_check_ack(struct nfp_flower_priv *app_priv)
   874→{
   875→	bool ret;
   876→
   877→	spin_lock_bh(&app_priv->mtu_conf.lock);
   878→	ret = app_priv->mtu_conf.ack;
   879→	spin_unlock_bh(&app_priv->mtu_conf.lock);
   880→
   881→	return ret;
   882→}
   883→
   884→static int
   885→nfp_flower_repr_change_mtu(struct nfp_app *app, struct net_device *netdev,
   886→			   int new_mtu)
   887→{
   888→	struct nfp_flower_priv *app_priv = app->priv;
   889→	struct nfp_repr *repr = netdev_priv(netdev);
   890→	int err;
   891→
   892→	/* Only need to config FW for physical port MTU change. */
   893→	if (repr->port->type != NFP_PORT_PHYS_PORT)
   894→		return 0;
   895→
   896→	if (!(app_priv->flower_ext_feats & NFP_FL_NBI_MTU_SETTING)) {
   897→		nfp_err(app->cpp, "Physical port MTU setting not supported\n");
   898→		return -EINVAL;
   899→	}
   900→
   901→	spin_lock_bh(&app_priv->mtu_conf.lock);
   902→	app_priv->mtu_conf.ack = false;
   903→	app_priv->mtu_conf.requested_val = new_mtu;
   904→	app_priv->mtu_conf.portnum = repr->dst->u.port_info.port_id;
   905→	spin_unlock_bh(&app_priv->mtu_conf.lock);
   906→
   907→	err = nfp_flower_cmsg_portmod(repr, netif_carrier_ok(netdev), new_mtu,
   908→				      true);
   909→	if (err) {
   910→		spin_lock_bh(&app_priv->mtu_conf.lock);
   911→		app_priv->mtu_conf.requested_val = 0;
   912→		spin_unlock_bh(&app_priv->mtu_conf.lock);
   913→		return err;
   914→	}
   915→
   916→	/* Wait for fw to ack the change. */
   917→	if (!wait_event_timeout(app_priv->mtu_conf.wait_q,
   918→				nfp_flower_check_ack(app_priv),
   919→				NFP_FL_REPLY_TIMEOUT)) {
   920→		spin_lock_bh(&app_priv->mtu_conf.lock);
   921→		app_priv->mtu_conf.requested_val = 0;
   922→		spin_unlock_bh(&app_priv->mtu_conf.lock);
   923→		nfp_warn(app->cpp, "MTU change not verified with fw\n");
   924→		return -EIO;
   925→	}
   926→
   927→	return 0;
   928→}
   929→
   930→static int nfp_flower_start(struct nfp_app *app)
   931→{
   932→	struct nfp_flower_priv *app_priv = app->priv;
   933→	int err;
   934→
   935→	if (app_priv->flower_en_feats & NFP_FL_ENABLE_LAG) {
   936→		err = nfp_flower_lag_reset(&app_priv->nfp_lag);
   937→		if (err)
   938→			return err;
   939→	}
   940→
   941→	err = flow_indr_dev_register(nfp_flower_indr_setup_tc_cb, app);
   942→	if (err)
   943→		return err;
   944→
   945→	err = nfp_tunnel_config_start(app);
   946→	if (err)
   947→		goto err_tunnel_config;
   948→
   949→	return 0;
   950→
   951→err_tunnel_config:
   952→	flow_indr_dev_unregister(nfp_flower_indr_setup_tc_cb, app,
   953→				 nfp_flower_setup_indr_tc_release);
   954→	return err;
   955→}
   956→
   957→static void nfp_flower_stop(struct nfp_app *app)
   958→{
   959→	nfp_tunnel_config_stop(app);
   960→
   961→	flow_indr_dev_unregister(nfp_flower_indr_setup_tc_cb, app,
   962→				 nfp_flower_setup_indr_tc_release);
   963→}
   964→
   965→static int
   966→nfp_flower_netdev_event(struct nfp_app *app, struct net_device *netdev,
   967→			unsigned long event, void *ptr)
   968→{
   969→	struct nfp_flower_priv *app_priv = app->priv;
   970→	int ret;
   971→
   972→	if (app_priv->flower_en_feats & NFP_FL_ENABLE_LAG) {
   973→		ret = nfp_flower_lag_netdev_event(app_priv, netdev, event, ptr);
   974→		if (ret & NOTIFY_STOP_MASK)
   975→			return ret;
   976→	}
   977→
   978→	ret = nfp_flower_internal_port_event_handler(app, netdev, event);
   979→	if (ret & NOTIFY_STOP_MASK)
   980→		return ret;
   981→
   982→	return nfp_tunnel_mac_event_handler(app, netdev, event, ptr);
   983→}
   984→
   985→const struct nfp_app_type app_flower = {
   986→	.id		= NFP_APP_FLOWER_NIC,
   987→	.name		= "flower",
   988→
   989→	.ctrl_cap_mask	= ~0U,
   990→	.ctrl_has_meta	= true,
   991→
   992→	.extra_cap	= nfp_flower_extra_cap,
   993→
   994→	.init		= nfp_flower_init,
   995→	.clean		= nfp_flower_clean,
   996→
   997→	.repr_change_mtu  = nfp_flower_repr_change_mtu,
   998→
   999→	.vnic_alloc	= nfp_flower_vnic_alloc,
  1000→	.vnic_init	= nfp_flower_vnic_init,
  1001→	.vnic_clean	= nfp_flower_vnic_clean,
  1002→
  1003→	.repr_preclean	= nfp_flower_repr_netdev_preclean,
  1004→	.repr_clean	= nfp_flower_repr_netdev_clean,
  1005→
  1006→	.repr_open	= nfp_flower_repr_netdev_open,
  1007→	.repr_stop	= nfp_flower_repr_netdev_stop,
  1008→
  1009→	.start		= nfp_flower_start,
  1010→	.stop		= nfp_flower_stop,
  1011→
  1012→	.netdev_event	= nfp_flower_netdev_event,
  1013→
  1014→	.ctrl_msg_rx	= nfp_flower_cmsg_rx,
  1015→
  1016→	.sriov_enable	= nfp_flower_sriov_enable,
  1017→	.sriov_disable	= nfp_flower_sriov_disable,
  1018→
  1019→	.eswitch_mode_get  = eswitch_mode_get,
  1020→	.dev_get	= nfp_flower_dev_get,
